GLITCH_SQUASHER_LOGO_B64 = ""

#   place base64 text data for logo inbetween these " " above


def _reconstruct_logo():
    """Decode embedded base64 logo to a temp PNG file and return the path."""
    if not GLITCH_SQUASHER_LOGO_B64:
        return None
    logo_path = os.path.join(tempfile.gettempdir(), "glitch_live_builder_logo.png")
    if not os.path.exists(logo_path):
        try:
            raw = base64.b64decode(GLITCH_SQUASHER_LOGO_B64)
            with open(logo_path, 'wb') as f:
                f.write(raw)
        except Exception:
            return None
    return logo_path


