# ─────────────────────────────────────────────────────────────
# UTILITY FUNCTIONS
# ─────────────────────────────────────────────────────────────
def run_cmd(cmd, shell=True, timeout=600):
    """Run a command and return (returncode, stdout, stderr)."""
    try:
        result = subprocess.run(
            cmd, shell=shell, capture_output=True, text=True,
            timeout=timeout
        )
        return result.returncode, result.stdout.strip(), result.stderr.strip()
    except subprocess.TimeoutExpired:
        return -1, "", "Command timed out"
    except Exception as e:
        return -1, "", str(e)


def human_size(size_bytes):
    """Convert bytes to human-readable size."""
    if size_bytes is None:
        return "Unknown"
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if abs(size_bytes) < 1024.0:
            return f"{size_bytes:.1f} {unit}"
        size_bytes /= 1024.0
    return f"{size_bytes:.1f} PB"


def get_current_hostname():
    """Get the current system hostname."""
    rc, out, _ = run_cmd("hostname")
    if rc == 0 and out:
        return out.strip()
    return "live-system"


def get_disk_free(path):
    """Get free disk space at path in bytes."""
    try:
        st = os.statvfs(path)
        return st.f_bavail * st.f_frsize
    except Exception:
        return 0


def get_root_used():
    """Get how much space the root filesystem uses (approx)."""
    rc, out, _ = run_cmd("df -B1 / | tail -1 | awk '{print $3}'")
    if rc == 0 and out:
        try:
            return int(out)
        except ValueError:
            pass
    return 0


# ─────────────────────────────────────────────────────────────
# SQUASHER WORKER THREAD
# ─────────────────────────────────────────────────────────────
class SquashWorker(QThread):
    """Background thread: squashfs preparation + automatic ISO build."""
    log_signal = pyqtSignal(str, str)       # message, level
    progress_signal = pyqtSignal(int)        # percentage 0-100
    step_signal = pyqtSignal(str)            # current step description
    finished_signal = pyqtSignal(bool, str)  # success, message

    def __init__(self, config):
        super().__init__()
        self.config = config
        self._cancelled = False
        self._lock = Lock()

    def cancel(self):
        with self._lock:
            self._cancelled = True

    def is_cancelled(self):
        with self._lock:
            return self._cancelled

    def log(self, msg, level="INFO"):
        self.log_signal.emit(msg, level)

    def exec_cmd(self, cmd, desc="", timeout=600):
        """Execute command with logging."""
        if desc:
            self.log(desc, "PROGRESS")
        rc, out, err = run_cmd(cmd, timeout=timeout)
        if rc != 0 and err:
            self.log(f"  stderr: {err}", "WARNING")
        return rc, out, err

    def run(self):
        try:
            self._run_squash()
        except Exception as e:
            self.log(f"Fatal error: {str(e)}", "ERROR")
            self.finished_signal.emit(False, str(e))

    def _run_squash(self):
        cfg = self.config
        work_dir = cfg['work_dir']
        distro_name = cfg['distro_name']
        hostname = cfg['hostname']
        cleanup_after = cfg.get('cleanup', True)
        iso_name = cfg.get('iso_name', distro_name + '.iso')
        system_name = cfg.get('system_name', distro_name)
        volume_name = cfg.get('volume_name', distro_name.upper()[:32])

        remastered = os.path.join(work_dir, "remastered")
        live_dir = os.path.join(work_dir, distro_name, "live")
        squashfs_out = os.path.join(live_dir, "filesystem.squashfs")
        iso_output = os.path.join(work_dir, iso_name)

        total_steps = 10
        current = 0

        def advance(desc):
            nonlocal current
            current += 1
            pct = int((current / total_steps) * 100)
            self.step_signal.emit(desc)
            self.progress_signal.emit(pct)
            self.log(f"── Step {current}/{total_steps}: {desc}", "INFO")

        # ── Step 1: Check & install dependencies ──
        advance("Checking and installing dependencies...")

        required_pkgs = [
            "squashfs-tools", "rsync", "live-boot", "live-boot-initramfs-tools",
        ]

        # Check which packages are missing on the HOST system
        # We check for actual file presence, not just dpkg status (handles broken states)
        missing = []
        for pkg in required_pkgs:
            rc, _, _ = run_cmd(f"dpkg -s {pkg} 2>/dev/null | grep -q '^Status:.*installed'")
            if rc != 0:
                missing.append(pkg)

        if missing:
            self.log(f"Missing packages: {', '.join(missing)}", "WARNING")
            self.log("Installing missing dependencies...", "PROGRESS")
            rc, _, err = self.exec_cmd("apt-get update -qq", "Updating package lists...", timeout=120)
            if rc != 0:
                self.log("apt-get update had warnings, continuing...", "WARNING")

            for pkg in missing:
                if self.is_cancelled():
                    self.finished_signal.emit(False, "Cancelled by user")
                    return
                rc, _, _ = self.exec_cmd(f"apt-get install -y -qq {pkg}", f"Installing {pkg}...", timeout=180)
                if rc == 0:
                    self.log(f"  Installed: {pkg}", "SUCCESS")
                else:
                    self.log(f"  Could not install: {pkg} (may be optional)", "WARNING")
        else:
            self.log("All dependencies satisfied.", "SUCCESS")

        if self.is_cancelled():
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 2: Prepare directories ──
        advance("Preparing working directories...")

        if os.path.exists(remastered):
            self.log(f"Removing existing remastered dir: {remastered}", "WARNING")
            shutil.rmtree(remastered, ignore_errors=True)

        os.makedirs(remastered, exist_ok=True)
        os.makedirs(live_dir, exist_ok=True)
        self.log(f"Created: {remastered}", "SUCCESS")
        self.log(f"Created: {live_dir}", "SUCCESS")

        if self.is_cancelled():
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 3: Rsync system ──
        advance("Rsyncing system (this may take a while)...")

        # Build exclusion list
        excludes = [
            "/dev/*", "/proc/*", "/sys/*", "/tmp/*", "/run/*",
            "/mnt/*", "/media/*", "/live/*", "/lib/live/mount/*",
            "/cdrom/*", "/initrd/*",
            "/var/cache/apt/archives/*", "/var/lib/apt/lists/*",
            "/var/log/*", "/root/.cache", "/root/.thumbnails",
	    "/home/x/Desktop/gocryptfs/",
            "/home/*/.cache", "/home/*/.thumbnails",
            "/swap.file", "/swapfile",
            "/usr/lib/live/mount/rootfs/*",
            "/usr/lib/live/mount/medium/*",
            "/usr/lib/live/mount/overlay/*",
        ]
        # Also exclude the working directory itself
        rel_work = work_dir.lstrip("/")
        if rel_work:
            excludes.append(f"/{rel_work}")

        exclude_args = " ".join([f'--exclude="{e}"' for e in excludes])
        rsync_cmd = f'rsync -aHAXS --numeric-ids --info=progress2 / "{remastered}" {exclude_args}'

        # Run rsync with live output parsing
        self.log("Running rsync... (streaming progress)", "PROGRESS")
        try:
            proc = subprocess.Popen(
                rsync_cmd, shell=True,
                stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                text=True, bufsize=1
            )
            last_pct = 0
            for line in proc.stdout:
                line = line.strip()
                if self.is_cancelled():
                    proc.kill()
                    self.finished_signal.emit(False, "Cancelled by user")
                    return
                # Parse rsync progress percentage
                match = re.search(r'(\d+)%', line)
                if match:
                    pct = int(match.group(1))
                    if pct != last_pct:
                        last_pct = pct
                        # Map rsync 0-100 to overall step 3 progress (22-44%)
                        overall = 22 + int(pct * 0.22)
                        self.progress_signal.emit(min(overall, 44))

            proc.wait()
            if proc.returncode != 0:
                self.log(f"rsync exited with code {proc.returncode} (some warnings are normal)", "WARNING")
        except Exception as e:
            self.log(f"rsync error: {e}", "ERROR")
            self.finished_signal.emit(False, f"rsync failed: {e}")
            return

        self.log("System rsync complete.", "SUCCESS")

        # Create essential empty directories
        for d in ["dev", "proc", "sys", "tmp", "run", "mnt", "media"]:
            os.makedirs(os.path.join(remastered, d), exist_ok=True)

        if self.is_cancelled():
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 4: Fix systemd / live boot config ──
        advance("Configuring systemd for live boot...")
        self._fix_systemd(remastered, hostname)

        if self.is_cancelled():
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 5: Ensure live-boot packages are functional ──
        advance("Ensuring live-boot packages are functional...")
        self._ensure_live_boot_packages(remastered)

        if self.is_cancelled():
            self._unmount_chroot(remastered)
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 6: Clean up remastered system ──
        advance("Cleaning up remastered system...")
        self._cleanup_remastered(remastered)

        if self.is_cancelled():
            self._unmount_chroot(remastered)
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 7: Generate initramfs inside chroot ──
        advance("Regenerating initramfs in chroot...")
        self._regenerate_initramfs(remastered)

        if self.is_cancelled():
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 8: Create squashfs ──
        advance("Creating filesystem.squashfs (this will take several minutes)...")

        if os.path.exists(squashfs_out):
            os.remove(squashfs_out)

        mksquashfs_cmd = (
            f'mksquashfs "{remastered}" "{squashfs_out}" '
            f'-comp xz -b 512k -Xbcj x86 -no-progress'
        )

        self.log("Running mksquashfs...", "PROGRESS")
        rc, out, err = run_cmd(mksquashfs_cmd, timeout=7200)
        if rc != 0:
            self.log(f"mksquashfs failed: {err}", "ERROR")
            self.finished_signal.emit(False, "Failed to create filesystem.squashfs")
            return

        if not os.path.isfile(squashfs_out):
            self.finished_signal.emit(False, "filesystem.squashfs was not created")
            return

        sq_size = os.path.getsize(squashfs_out)
        self.log(f"filesystem.squashfs created: {human_size(sq_size)}", "SUCCESS")

        if self.is_cancelled():
            self.finished_signal.emit(False, "Cancelled by user")
            return

        # ── Step 9: Copy vmlinuz and initrd to live/ ──
        advance("Copying kernel and initrd to live/ directory...")
        self._copy_boot_files(remastered, live_dir)

        # ── Cleanup remastered ──
        if cleanup_after:
            self.log("Cleaning up remastered working directory...", "PROGRESS")
            shutil.rmtree(remastered, ignore_errors=True)
            self.log("Remastered directory removed.", "SUCCESS")
        else:
            self.log(f"Remastered directory preserved at: {remastered}", "INFO")

        # ── Step 10: Build ISO ──
        advance("Building bootable ISO (extracting bundled bootfiles + xorriso)...")
        iso_path, iso_size = self._build_iso(
            parent_dir=os.path.join(work_dir, distro_name),
            iso_output=iso_output,
            system_name=system_name,
            volume_name=volume_name,
        )

        # ── Done ──
        self.progress_signal.emit(100)
        result_msg = (
            f"Live boot files:\n"
            f"  {live_dir}/\n\n"
            f"Contents:\n"
            f"  filesystem.squashfs  ({human_size(sq_size)})\n"
        )
        for f in os.listdir(live_dir):
            if f != "filesystem.squashfs":
                fpath = os.path.join(live_dir, f)
                fsize = human_size(os.path.getsize(fpath)) if os.path.isfile(fpath) else ""
                result_msg += f"  {f}  ({fsize})\n"

        if iso_path:
            result_msg += f"\n── ISO Built Successfully ──\n"
            result_msg += f"  Path: {iso_path}\n"
            result_msg += f"  Size: {iso_size}\n"
            result_msg += f"\nWrite to USB:\n  dd if={iso_path} of=/dev/sdX bs=4M status=progress\n"
        else:
            result_msg += "\n[WARNING] ISO build failed — squashfs files are intact.\n"

        self.finished_signal.emit(True, result_msg)

    def _build_iso(self, parent_dir, iso_output, system_name, volume_name):
        """Write embedded ISO builder script to /tmp and execute it.
        Returns (iso_path, size_str) on success, (None, None) on failure."""
        script_path = "/tmp/_glitch_iso_builder.sh"
        try:
            with open(script_path, 'w') as f:
                f.write(ISO_BUILDER_SCRIPT)
            os.chmod(script_path, 0o755)
        except Exception as e:
            self.log(f"Failed to write ISO builder script: {e}", "ERROR")
            return None, None

        self.log(f"ISO builder script written to {script_path}", "INFO")
        self.log(f"Building: {iso_output}", "PROGRESS")

        try:
            proc = subprocess.Popen(
                ["/bin/bash", script_path,
                 parent_dir, os.path.basename(iso_output),
                 system_name, volume_name, iso_output],
                stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                text=True, bufsize=1
            )
            iso_path = None
            iso_size = None
            for line in proc.stdout:
                line = line.strip()
                if not line:
                    continue
                if line.startswith("STEP:"):
                    self.log(line[5:].strip(), "PROGRESS")
                elif line.startswith("DETECTED:"):
                    self.log(line[9:].strip(), "INFO")
                elif line.startswith("ISO_SUCCESS:"):
                    parts = line[12:].strip()
                    # "path (size)"
                    if " (" in parts:
                        iso_path = parts[:parts.rfind(" (")]
                        iso_size = parts[parts.rfind("(")+1:parts.rfind(")")]
                    else:
                        iso_path = parts
                        iso_size = "unknown"
                    self.log(f"ISO created: {iso_path} ({iso_size})", "SUCCESS")
                elif line.startswith("ISO_FAILED:"):
                    self.log(line[11:].strip(), "ERROR")
                elif "error" in line.lower() or "failed" in line.lower():
                    self.log(line, "WARNING")
                else:
                    self.log(line, "INFO")

            proc.wait()
            if proc.returncode != 0:
                self.log(f"ISO builder exited with code {proc.returncode}", "ERROR")
                return None, None

            return iso_path, iso_size

        except Exception as e:
            self.log(f"ISO builder exception: {e}", "ERROR")
            return None, None
        finally:
            try:
                os.remove(script_path)
            except OSError:
                pass

    def _fix_systemd(self, work, hostname):
        """Fix systemd and filesystem configuration for live boot."""
        self.log("Preparing live-boot filesystem configuration...", "PROGRESS")

        # Create essential empty directories
        for d in ["dev", "proc", "sys", "run/systemd", "var/lib/systemd",
                   "etc/systemd/system", "etc/live", "etc/live/boot"]:
            os.makedirs(os.path.join(work, d), exist_ok=True)

        # ── Empty fstab (live-boot manages its own mounts) ──
        # Save original fstab for reference, then empty it
        fstab_path = os.path.join(work, "etc", "fstab")
        fstab_orig = os.path.join(work, "etc", "fstab.orig")
        if os.path.exists(fstab_path):
            shutil.copy2(fstab_path, fstab_orig)
        with open(fstab_path, 'w') as f:
            f.write("")  # Empty — live-boot handles mounts
        self.log("fstab emptied (live-boot manages mounts).", "SUCCESS")

        # ── Set hostname ──
        hostname_path = os.path.join(work, "etc", "hostname")
        with open(hostname_path, 'w') as f:
            f.write(hostname + '\n')

        hosts_path = os.path.join(work, "etc", "hosts")
        with open(hosts_path, 'w') as f:
            f.write(f"127.0.0.1\tlocalhost\n")
            f.write(f"127.0.1.1\t{hostname}\n")
            f.write(f"::1\t\tlocalhost ip6-localhost ip6-loopback\n")
            f.write(f"ff02::1\t\tip6-allnodes\n")
            f.write(f"ff02::2\t\tip6-allrouters\n")
        self.log(f"Hostname set to: {hostname}", "SUCCESS")

        # ── machine-id ──
        machine_id_path = os.path.join(work, "etc", "machine-id")
        if not os.path.exists(machine_id_path):
            rc, _, _ = run_cmd(f'systemd-machine-id-setup --root="{work}"')
            if rc != 0:
                rc2, uuid_out, _ = run_cmd("cat /proc/sys/kernel/random/uuid")
                if rc2 == 0:
                    with open(machine_id_path, 'w') as f:
                        f.write(uuid_out.replace('-', '') + '\n')

        # ── RESUME=none (prevents initramfs from looking for swap) ──
        resume_dir = os.path.join(work, "etc", "initramfs-tools", "conf.d")
        os.makedirs(resume_dir, exist_ok=True)
        with open(os.path.join(resume_dir, "resume"), 'w') as f:
            f.write("RESUME=none\n")
        self.log("Set RESUME=none in initramfs config.", "SUCCESS")

        # ── resolv.conf (for chroot network access) ──
        resolv_path = os.path.join(work, "etc", "resolv.conf")
        # Back up the original
        if os.path.exists(resolv_path) or os.path.islink(resolv_path):
            try:
                os.remove(resolv_path)
            except OSError:
                pass
        with open(resolv_path, 'w') as f:
            f.write("nameserver 8.8.8.8\n")
            f.write("nameserver 8.8.4.4\n")

        self.log("Filesystem configuration complete.", "SUCCESS")

    def _ensure_live_boot_packages(self, work):
        """Ensure live-boot and live-boot-initramfs-tools are properly installed in the chroot.
        
        This is THE critical step — without these packages properly installed,
        update-initramfs won't include the live boot hook/scripts, and the
        resulting initrd will not be able to find/mount filesystem.squashfs.
        """
        self.log("Verifying live-boot packages inside remastered system...", "PROGRESS")

        # Mount essential filesystems for chroot operations
        self._mount_chroot(work)

        try:
            # Check if the critical files exist (not just dpkg status)
            critical_files = [
                "usr/bin/live-boot",
                "usr/share/initramfs-tools/hooks/live",
                "usr/share/initramfs-tools/scripts/live",
                "usr/lib/live/boot/9990-main.sh",
            ]

            missing_files = []
            for f in critical_files:
                if not os.path.exists(os.path.join(work, f)):
                    missing_files.append(f)

            if missing_files:
                self.log(f"Missing critical live-boot files: {', '.join(missing_files)}", "WARNING")
                self.log("Reinstalling live-boot packages inside chroot...", "PROGRESS")

                # Force reinstall inside chroot with network access
                rc, _, err = run_cmd(
                    f'chroot "{work}" apt-get update -qq', timeout=120
                )
                if rc != 0:
                    self.log(f"apt-get update in chroot had issues: {err}", "WARNING")

                for pkg in ["live-boot", "live-boot-initramfs-tools"]:
                    rc, _, err = run_cmd(
                        f'chroot "{work}" apt-get install --reinstall -y -qq {pkg}',
                        timeout=180
                    )
                    if rc == 0:
                        self.log(f"  Reinstalled {pkg} in chroot.", "SUCCESS")
                    else:
                        self.log(f"  Failed to reinstall {pkg}: {err}", "WARNING")
                        # Try dpkg --configure as fallback
                        run_cmd(f'chroot "{work}" dpkg --configure -a', timeout=60)

                # Verify again after install
                still_missing = []
                for f in critical_files:
                    if not os.path.exists(os.path.join(work, f)):
                        still_missing.append(f)

                if still_missing:
                    # Last resort: copy from host system if available
                    self.log("Attempting to copy live-boot files from host system...", "WARNING")
                    for f in still_missing:
                        host_path = os.path.join("/", f)
                        target_path = os.path.join(work, f)
                        if os.path.exists(host_path):
                            os.makedirs(os.path.dirname(target_path), exist_ok=True)
                            if os.path.isdir(host_path):
                                shutil.copytree(host_path, target_path, dirs_exist_ok=True)
                            else:
                                shutil.copy2(host_path, target_path)
                            self.log(f"  Copied from host: {f}", "SUCCESS")
                        else:
                            self.log(f"  CRITICAL: {f} not found on host either!", "ERROR")
            else:
                self.log("All critical live-boot files present.", "SUCCESS")

            # Also ensure the live-boot dpkg status is clean
            # Fix "purge ok installed" states
            rc, _, _ = run_cmd(f'chroot "{work}" dpkg --configure -a', timeout=60)

        finally:
            # DON'T unmount here — we'll keep mounts for initramfs step
            pass

        self.log("Live-boot package verification complete.", "SUCCESS")

    def _cleanup_remastered(self, work):
        """Clean up the remastered system before squashing."""
        cleanup_files = [
            "var/lib/alsa/asound.state",
            "root/.bash_history",
            "root/.xsession-errors",
            "root/.xsession-errors.old",
            "etc/blkid-cache",
        ]
        for f in cleanup_files:
            full = os.path.join(work, f)
            if os.path.exists(full):
                try:
                    os.remove(full)
                except OSError:
                    pass

        # Remove persistent udev rules
        udev_dir = os.path.join(work, "etc", "udev", "rules.d")
        if os.path.exists(udev_dir):
            for f in os.listdir(udev_dir):
                if f.startswith("70-persistent"):
                    try:
                        os.remove(os.path.join(udev_dir, f))
                    except OSError:
                        pass

        # Remove DHCP leases
        for pattern_dir in ["var/lib/dhcp", "var/lib/dhcpcd"]:
            full = os.path.join(work, pattern_dir)
            if os.path.exists(full):
                for f in os.listdir(full):
                    if "lease" in f:
                        try:
                            os.remove(os.path.join(full, f))
                        except OSError:
                            pass

        # Clear temp dirs
        for d in ["var/tmp", "tmp"]:
            full = os.path.join(work, d)
            if os.path.exists(full):
                for item in os.listdir(full):
                    item_path = os.path.join(full, item)
                    try:
                        if os.path.isdir(item_path):
                            shutil.rmtree(item_path)
                        else:
                            os.remove(item_path)
                    except OSError:
                        pass

        # Set proper permissions
        tmp_dir = os.path.join(work, "tmp")
        if os.path.exists(tmp_dir):
            os.chmod(tmp_dir, 0o1777)
        run_dir = os.path.join(work, "run")
        if os.path.exists(run_dir):
            os.chmod(run_dir, 0o755)

        self.log("Cleanup complete.", "SUCCESS")

    def _mount_chroot(self, work):
        """Bind-mount essential filesystems for chroot operations."""
        mounts = [
            ("/proc", os.path.join(work, "proc")),
            ("/sys", os.path.join(work, "sys")),
            ("/dev", os.path.join(work, "dev")),
            ("/dev/pts", os.path.join(work, "dev", "pts")),
        ]
        for src, dst in mounts:
            os.makedirs(dst, exist_ok=True)
            # Check if already mounted
            rc, out, _ = run_cmd(f'mountpoint -q "{dst}"')
            if rc != 0:
                run_cmd(f'mount --bind {src} "{dst}"')

    def _unmount_chroot(self, work):
        """Unmount chroot filesystems safely."""
        for target in ["dev/pts", "dev", "sys", "proc"]:
            mount_point = os.path.join(work, target)
            # Try normal unmount first, then lazy as fallback
            rc, _, _ = run_cmd(f'umount "{mount_point}" 2>/dev/null')
            if rc != 0:
                run_cmd(f'umount -l "{mount_point}" 2>/dev/null')

    def _regenerate_initramfs(self, work):
        """Regenerate initramfs with live-boot support and verify it.
        
        CRITICAL INSIGHT: The rsynced initrd from /boot likely ALREADY contains
        live-boot scripts (if the source system had live-boot installed).
        Systemback's approach is to simply KEEP that initrd without rebuilding.
        
        Our approach:
        1. Back up the rsynced initrd (it probably works already)
        2. Try to rebuild with proper bind mounts 
        3. Verify the rebuilt initrd has live scripts
        4. If rebuild broke it, RESTORE the backup
        
        Chroot bind mounts should already be active from _ensure_live_boot_packages.
        """
        self.log("Preparing initramfs for live boot...", "PROGRESS")

        boot_dir = os.path.join(work, "boot")
        if not os.path.isdir(boot_dir):
            self.log("CRITICAL: No /boot directory found!", "ERROR")
            self._unmount_chroot(work)
            return

        # Find current initrd files
        initrd_files = sorted(
            [f for f in os.listdir(boot_dir) if f.startswith("initrd")],
            reverse=True
        )

        if not initrd_files:
            self.log("CRITICAL: No initrd found in /boot!", "ERROR")
            self._unmount_chroot(work)
            return

        initrd_path = os.path.join(boot_dir, initrd_files[0])
        backup_path = initrd_path + ".pre-squash-backup"

        # ── Step A: Check if the EXISTING rsynced initrd already has live scripts ──
        self.log(f"Checking rsynced initrd: {initrd_files[0]}...", "PROGRESS")
        rsynced_has_live = self._verify_initrd_has_live(initrd_path, work)

        if rsynced_has_live:
            self.log("Rsynced initrd ALREADY contains live-boot scripts.", "SUCCESS")
            self.log("Backing it up before attempting rebuild...", "PROGRESS")
        else:
            self.log("Rsynced initrd does NOT contain live-boot scripts.", "WARNING")
            self.log("Will attempt to rebuild with live-boot hooks...", "PROGRESS")

        # Back up the rsynced initrd regardless
        shutil.copy2(initrd_path, backup_path)

        # ── Step B: Attempt to rebuild initramfs with proper chroot ──
        self._mount_chroot(work)

        # Verify live-boot hook exists before rebuilding
        hook_path = os.path.join(work, "usr", "share", "initramfs-tools", "hooks", "live")
        script_path = os.path.join(work, "usr", "share", "initramfs-tools", "scripts", "live")

        if not os.path.exists(hook_path) or not os.path.exists(script_path):
            self.log("Live-boot hooks not found — skipping rebuild, using rsynced initrd.", "WARNING")
            if os.path.exists(backup_path):
                shutil.copy2(backup_path, initrd_path)
            self._unmount_chroot(work)
            return

        self.log("Live-boot hook and script confirmed present. Rebuilding...", "PROGRESS")

        rc, out, err = run_cmd(f'chroot "{work}" update-initramfs -u -k all', timeout=600)
        if rc != 0:
            self.log(f"update-initramfs had issues: {err}", "WARNING")

        # ── Step C: Verify the rebuilt initrd ──
        rebuilt_has_live = self._verify_initrd_has_live(initrd_path, work)

        if rebuilt_has_live:
            self.log("VERIFIED: Rebuilt initrd contains live-boot scripts.", "SUCCESS")
            # Clean up backup
            if os.path.exists(backup_path):
                os.remove(backup_path)
        else:
            # Rebuild BROKE the initrd — restore the backup
            self.log("Rebuilt initrd LOST live-boot scripts!", "ERROR")

            if rsynced_has_live:
                self.log("Restoring backed-up rsynced initrd (which had live scripts).", "WARNING")
                shutil.copy2(backup_path, initrd_path)
                os.remove(backup_path)
                self.log("Original rsynced initrd restored.", "SUCCESS")
            else:
                self.log("Neither rsynced nor rebuilt initrd has live-boot scripts!", "ERROR")
                self.log("The live system may NOT boot. Ensure live-boot is installed on the source system.", "ERROR")
                if os.path.exists(backup_path):
                    os.remove(backup_path)

        # Unmount chroot filesystems
        self._unmount_chroot(work)

    def _verify_initrd_has_live(self, initrd_path, work):
        """Extract an initrd and check if it contains live-boot scripts.
        Returns True if /scripts/live is found inside the initrd."""
        if not os.path.isfile(initrd_path):
            return False

        verify_dir = os.path.join(work, "tmp", "_initrd_verify")
        if os.path.exists(verify_dir):
            shutil.rmtree(verify_dir, ignore_errors=True)
        os.makedirs(verify_dir, exist_ok=True)

        rc, _, _ = run_cmd(f'unmkinitramfs "{initrd_path}" "{verify_dir}" 2>/dev/null', timeout=60)
        if rc != 0:
            shutil.rmtree(verify_dir, ignore_errors=True)
            return False

        found_live = False
        for root_dir, dirs, files in os.walk(verify_dir):
            if "live" in files:
                parent = os.path.basename(root_dir)
                if parent == "scripts":
                    found_live = True
                    break

        shutil.rmtree(verify_dir, ignore_errors=True)
        return found_live

    def _copy_boot_files(self, remastered, live_dir):
        """Copy vmlinuz and initrd from remastered /boot to live/ directory."""
        boot_dir = os.path.join(remastered, "boot")

        if not os.path.isdir(boot_dir):
            self.log("No /boot directory found in remastered system!", "ERROR")
            return

        # Find the latest vmlinuz
        vmlinuz_files = sorted(
            [f for f in os.listdir(boot_dir) if f.startswith("vmlinuz")],
            reverse=True
        )
        # Find the latest initrd
        initrd_files = sorted(
            [f for f in os.listdir(boot_dir) if f.startswith("initrd") or f.startswith("initramfs")],
            reverse=True
        )

        if vmlinuz_files:
            src = os.path.join(boot_dir, vmlinuz_files[0])
            dst = os.path.join(live_dir, "vmlinuz")
            shutil.copy2(src, dst)
            self.log(f"Copied: {vmlinuz_files[0]} → live/vmlinuz ({human_size(os.path.getsize(dst))})", "SUCCESS")
        else:
            self.log("WARNING: No vmlinuz found in /boot!", "ERROR")

        if initrd_files:
            src = os.path.join(boot_dir, initrd_files[0])
            # Determine correct extension
            if initrd_files[0].endswith(".gz"):
                dst_name = "initrd.gz"
            else:
                dst_name = "initrd.img"
            dst = os.path.join(live_dir, dst_name)
            shutil.copy2(src, dst)
            self.log(f"Copied: {initrd_files[0]} → live/{dst_name} ({human_size(os.path.getsize(dst))})", "SUCCESS")
        else:
            self.log("WARNING: No initrd found in /boot!", "ERROR")


# ─────────────────────────────────────────────────────────────
# MAIN WINDOW
# ─────────────────────────────────────────────────────────────
class GlitchLiveBuilder(QMainWindow):
    def __init__(self):
        super().__init__()
        self.worker = None
        self.setWindowTitle("Glitch Linux Live System Builder")
        self.setMinimumSize(800, 700)
        self.resize(900, 780)

        # Set window icon
        logo_path = _reconstruct_logo()
        if logo_path and os.path.exists(logo_path):
            self.setWindowIcon(QIcon(logo_path))

        # Central widget
        central = QWidget()
        self.setCentralWidget(central)
        self.main_layout = QVBoxLayout(central)
        self.main_layout.setContentsMargins(24, 16, 24, 16)
        self.main_layout.setSpacing(8)

        # Stacked pages
        self.stack = QStackedWidget()
        self.main_layout.addWidget(self.stack)

        # Build pages
        self._build_config_page()
        self._build_progress_page()
        self._build_done_page()

        self.stack.setCurrentIndex(0)
        self.show()

    # ── Page 0: Configuration ──
    def _build_config_page(self):
        from PyQt5.QtWidgets import QScrollArea

        page = QWidget()
        outer_layout = QVBoxLayout(page)
        outer_layout.setSpacing(6)
        outer_layout.setContentsMargins(0, 0, 0, 0)

        # ── Header with logo (fixed, not scrolled) ──
        header_widget = QWidget()
        header_layout = QHBoxLayout(header_widget)
        header_layout.setContentsMargins(0, 0, 0, 0)

        logo_path = _reconstruct_logo()
        if logo_path and os.path.exists(logo_path):
            logo_label = QLabel()
            pixmap = QPixmap(logo_path)
            logo_label.setPixmap(pixmap.scaled(52, 52, Qt.KeepAspectRatio, Qt.SmoothTransformation))
            header_layout.addWidget(logo_label)

        title_layout = QVBoxLayout()
        title_layout.setSpacing(2)
        title = QLabel("Glitch Linux Live System Builder")
        title.setObjectName("title")
        title_layout.addWidget(title)

        subtitle = QLabel("Build a bootable live ISO from your running system!")
        subtitle.setObjectName("subtitle")
        subtitle.setWordWrap(True)
        title_layout.addWidget(subtitle)
        header_layout.addLayout(title_layout)
        header_layout.addStretch()
        outer_layout.addWidget(header_widget)

        # ── Compact system info bar (single line, no big card) ──
        current_host = get_current_hostname()
        root_used = get_root_used()
        rc, kernel_ver, _ = run_cmd("uname -r")
        kernel = kernel_ver if rc == 0 else "Unknown"

        info_bar = QLabel(
            f"  Hostname: {current_host}   │   Kernel: {kernel}   │   Root used: ~{human_size(root_used)}"
        )
